mapper.select:
SELECT tshcp.*
FROM esg.tb_safety_health_comm_plan tshcp
WHERE tshcp.comp_id = #{compId}

    AND tshcp.write_year = #{writeYear}
    AND tshcp.doc_type = #{docType}
    AND tshcp.doc_no = #{docNo}

ORDER BY tshcp.write_year DESC, tshcp.doc_no DESC, tshcp.use_yn DESC

SELECT tshcpd.*
FROM esg.tb_safety_health_comm_plan_detail tshcpd
WHERE tshcpd.comp_id = #{compId}
    AND tshcpd.write_year = #{writeYear}
    AND tshcpd.doc_type = #{docType}
    AND tshcpd.doc_no = #{docNo}
    AND tshcpd.content_type = #{contentType}
ORDER BY tshcpd.use_yn DESC, tshcpd.ord_seq ASC

mapper.update:
UPDATE esg.tb_safety_health_comm_plan
SET
    title = #{title},
    hr_id = #{hrId},
    hr_nm = #{hrNm},
    write_dt = #{writeDt},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
  AND comp_id = #{compId}

UPDATE esg.tb_safety_health_comm_plan
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
  AND comp_id = #{compId}

UPDATE esg.tb_safety_health_comm_plan_detail
SET
    content = #{content},
    period = #{period},
    subject = #{subject},
    method = #{method},
    ord_seq = #{ordSeq},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
  AND doc_seq = #{docSeq}
  AND comp_id = #{compId}

UPDATE esg.tb_safety_health_comm_plan_detail
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
  AND doc_seq = #{docSeq}
  AND comp_id = #{compId}
